mapper.select:
select * from transaction_record


        and (user_name like concat('%', #{keyword}, '%')
        or transaction_no like concat('%', #{keyword}, '%'))


        and type = #{type}


        and create_time >= #{startDate}


        and create_time <= #{endDate}


order by create_time desc

select ifnull(sum(amount), 0) from transaction_record
where amount > 0

    and create_time >= #{startDate}


    and create_time <= #{endDate}

select ifnull(sum(amount), 0) from transaction_record
where amount < 0

    and create_time >= #{startDate}


    and create_time <= #{endDate}

select type, sum(case when amount > 0 then amount else 0 end) as income, sum(case when amount < 0 then -amount else 0 end) as expense, count(*) as count from transaction_record
and create_time >= #{startDate}
and create_time <= #{endDate}
group by type order by case type when 'recharge' then 1 when 'payment' then 2 when 'refund' then 3 when 'deposit_freeze' then 4 when 'deposit_unfreeze' then 5 when 'deposit_deduct' then 6 else 7 end

select ifnull(sum(amount), 0) from transaction_record
where type = #{type}

    and DATE(create_time) >= #{startDate}


    and DATE(create_time) <= #{endDate}
